const body = $input.first().json.body;
const now = new Date().toLocaleString('en-US', {
  timeZone: 'America/Los_Angeles',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

const fields = [
  ['contact_name', 'Contact'],
  ['contact_method', 'Best Way to Reach You'],
  ['pricing', 'Current Pricing'],
  ['service_area', 'Service Area'],
  ['partner_clinics', 'Partner Clinics'],
  ['monthly_volume', 'Monthly Volume'],
  ['hours', 'Hours'],
  ['tier', 'Tier Interest'],
  ['photos', 'Photos Available'],
  ['photo_link', 'Photo Upload Link'],
  ['demo_feedback', 'Demo Site Feedback'],
  ['corrections', 'Corrections'],
  ['anything_else', 'Other Notes']
];

const summary = {};
for (const [key, label] of fields) {
  const val = body && body[key];
  if (val && String(val).trim()) {
    summary[label] = String(val).trim();
  }
}

return [{
  json: {
    timestamp: now,
    submission: summary,
    raw: body
  }
}];
